#include <bits/stdc++.h>using namespace std; int main(){  	long long t;	cin>>t;	while(t--){	    long long n;cin>>n;	    vector<long long> arr(n);	    for(int i=0;i<n;i++){	        cin>>arr[i];	    }	    	    	    vector<long long> suffSum(n+1);	    suffSum[n] = 0;	    suffSum[n-1] = (arr[n-1]);	    for(int i=n-2;i>=0;i--){	        suffSum[i] = (arr[i]+suffSum[i+1]);	    }	    	    long long ans = -suffSum[1];	    long long sum = arr[0];	    for(int i=1;i<n;i++){	        ans = max(ans, sum-suffSum[i+1]);	        sum += abs(arr[i]);	    }	    	    cout<<ans<<endl;	}}